            primary, secondary = c2, c1
            pp, sp = p2, p1
        seed_pairs.append((primary, secondary, pp, sp))
        used_in_pair.add(secondary)
        used_in_pair.add(primary)

    # Step 3: Find Hamiltonian path/cycle for each color group
    def valid_edge(p1, p2):
        dr = abs(p1[0] - p2[0])
        dc = abs(p1[1] - p2[1])
        if dr == 0 and dc > 0:
            return True
        if dc == 0 and dr > 0:
            return True
        if dr == dc and dr > 0:
            return True
        return False

    def draw_line(p1, p2):
        cells = [p1]
        dr = p2[0] - p1[0]
        dc = p2[1] - p1[1]
        steps = max(abs(dr), abs(dc))
        sr = (1 if dr > 0 else (-1 if dr < 0 else 0))
        sc = (1 if dc > 0 else (-1 if dc < 0 else 0))
        r, c = p1
        for _ in range(steps):
            r += sr
            c += sc
            cells.append((r, c))
        return cells

    def find_hamiltonian(vertices):
        n = len(vertices)
        if n == 0:
            return None, False
        if n == 1:
            return [vertices[0]], False

        adj = [[False]*n for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                if valid_edge(vertices[i], vertices[j]):
                    adj[i][j] = adj[j][i] = True

        best_path = None
        is_cycle = False

        def backtrack(path, visited):
            nonlocal best_path, is_cycle
            if is_cycle:
                return
            if len(path) == n:
                if adj[path[0]][path[-1]]:
                    best_path = path[:]
                    is_cycle = True
                    return
                if best_path is None:
                    best_path = path[:]
                return
            last = path[-1]
            for nxt in range(n):
                if not visited[nxt] and adj[last][nxt]:
                    visited[nxt] = True
                    path.append(nxt)
                    backtrack(path, visited)
                    path.pop()
                    visited[nxt] = False
                    if is_cycle:
                        return

        for start in range(n):
            visited = [False] * n
            visited[start] = True
            backtrack([start], visited)
            if is_cycle:
                break

        if best_path is not None:
            return [vertices[i] for i in best_path], is_cycle
        return None, False

    # Step 4: Draw everything
    output = [[0]*W for _ in range(H)]
    drawn = {}

    for color, pixels in color_pixels.items():
        path, is_cycle = find_hamiltonian(pixels)
        if path is None:
            drawn[color] = set(pixels)
        else:
            cells = set()
            for i in range(len(path) - 1):
                for cell in draw_line(path[i], path[i+1]):
                    cells.add(cell)
            if is_cycle:
                for cell in draw_line(path[-1], path[0]):
                    cells.add(cell)
            drawn[color] = cells

    # Process seed pairs
    for primary, secondary, pp, sp in seed_pairs:
        offset = (sp[0] - pp[0], sp[1] - pp[1])
        primary_cells = drawn[primary]
        shifted_cells = set()
        for (r, c) in primary_cells:
            nr, nc = r + offset[0], c + offset[1]
            if 0 <= nr < H and 0 <= nc < W:
                shifted_cells.add((nr, nc))
        shifted_cells -= primary_cells
        drawn[secondary] = shifted_cells

    for color, cells in drawn.items():
        for (r, c) in cells:
            if 0 <= r < H and 0 <= c < W:
                output[r][c] = color

    return output

